# 输入获取
n = int(input())
capacitys = [input() for _ in range(n)]


def calc(cap):
    ans = 0

    num = []
    for i in range(len(cap)):
        c = cap[i]

        if '0' <= c <= '9':
            num.append(c)
        else:
            if c == 'M':
                ans += int("".join(num))
            elif c == 'G':
                ans += int("".join(num)) * 1024
            elif c == 'T':
                ans += int("".join(num)) * 1024 * 1024

            num = []

    return ans


# 算法入口
def getResult():
    capacitys.sort(key=lambda x: calc(x))

    for cap in capacitys:
        print(cap)


# 算法调用
getResult()
